CODE_EXAMPLE:
public abstract class DataExporter {
  public void Export() {
    Open();
    WriteData();
    Close();
  }

  protected virtual void Open() => Console.WriteLine("Open");
  protected abstract void WriteData();
  protected virtual void Close() => Console.WriteLine("Close");
}

public class CsvExporter : DataExporter {
  protected override void WriteData() => Console.WriteLine("Write CSV");
}

public class JsonExporter : DataExporter {
  protected override void WriteData() => Console.WriteLine("Write JSON");
}

